   219→  private void mapToPathItems(OWLClass resourceClass) {
   220→    String name = nameResolver.resolve(resourceClass);
   221→    SetMultimap<String, String> annotations = OntologyUtil.annotationsOf(resourceClass, ontology);
   222→    String prefLabel = StringUtils.defaultIfBlank(String.join(",", annotations.get("prefLabel")),
   223→        name);
   224→    String definition = OntologyUtil.getDescription(resourceClass, ontology);
   225→    PathItem singlePath = deepCopy(config.getTemplates().getSinglePathItem(), PathItem.class);
   226→    singlePath.setSummary("Single " + StringUtils.defaultIfBlank(prefLabel, name));
   227→    singlePath.setDescription(definition);
   228→    String parameterName = name + "Id";
   229→    openApi.addTagsItem(new Tag().name(name).description(definition));
   230→    Content resourceContent = new Content().addMediaType("application/json",
   231→        new MediaType().schema(new ComposedSchema().$ref(name)));
   232→    final Set<String> security = securityGroupsForResource(resourceClass);
   233→    Stream.of(PathItem.HttpMethod.GET, PathItem.HttpMethod.PUT, PathItem.HttpMethod.PATCH, PathItem.HttpMethod.DELETE)
   234→        .forEach(httpMethod -> {
   235→              Operation defaultOperation = singlePath.readOperationsMap().getOrDefault(httpMethod, new Operation());
   236→          defaultOperation.addParametersItem(new Parameter().name(parameterName).in("path").schema(new StringSchema()))
   237→                  .getResponses()
